import type { RangeItem } from '../types/range-legend.js';

export const getFilteredItems = (items: RangeItem[]) => {
  const filteredItems = items.filter(
    (item) => ![item.from, item.to].includes(NaN),
  );

  const itemsMap = new Map();

  filteredItems.forEach((item) => {
    const mapKey = `${item.from}${item.to}`;

    if (!itemsMap.has(mapKey)) {
      itemsMap.set(mapKey, item);
    }
  });

  return [...itemsMap.values()];
};
